  function cloneFrom(code, overrides){
    var base = COPY[code || 'en'] || COPY.en;
    var out = {};
    Object.keys(base).forEach(function(key){ out[key] = base[key]; });
    Object.keys(overrides || {}).forEach(function(key){ out[key] = overrides[key]; });
    return out;
  }

  COPY.br = COPY.br || cloneFrom('pt', {});
  COPY.pt = COPY.pt || cloneFrom('br', {});

  function esc(value){
    return String(value == null ? '' : value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function currentLocale(){
    try{
      if(typeof currentLang === 'string' && currentLang) return currentLang;
      if(window.currentLang) return window.currentLang;
    }catch(err){}
    var stored = '';
    try{ stored = localStorage.getItem('coinProofPathLang') || localStorage.getItem('cryptoAcademyLang') || ''; }catch(err){}
    return stored || document.documentElement.lang || 'en';
  }

  function copy(){
    var lang = currentLocale();
    return COPY[lang] || COPY.en;
  }

  function isRtl(){
    return currentLocale() === 'ar';
  }

  function basePrefix(){
    try{
      if(typeof getBasePrefix === 'function') return getBasePrefix();
    }catch(err){}
    return '';
  }

  function routeToAbout(){
    return basePrefix() + '#about';
  }

  function routeToPartner(){
    return basePrefix() + '#partner';
  }

  function mailto(){
    return 'mailto:' + EMAIL + '?subject=' + encodeURIComponent('Coin ProofPath Inquiry');
  }

  function renderTeach(items){
    return (items || []).map(function(item, index){
      return '<article class="about-teach-card"><span>' + esc(String(index + 1).padStart(2, '0')) + '</span><strong>' + esc(item) + '</strong></article>';
    }).join('');
  }

  function renderPrinciples(items){
    return (items || []).map(function(item){
      return '<article class="about-principle-card"><h3>' + esc(item[0]) + '</h3><p>' + esc(item[1]) + '</p></article>';
    }).join('');
  }

  function renderList(items){
    return (items || []).map(function(item){
      return '<li><span aria-hidden="true"></span>' + esc(item) + '</li>';
    }).join('');
  }

  function renderPaths(items){
    return (items || []).map(function(item, index){
      return '<article class="about-path-card"><div class="about-path-index">' + esc(String(index + 1)) + '</div><h3>' + esc(item[0]) + '</h3><p>' + esc(item[1]) + '</p></article>';
    }).join('');
  }

